// ── Section 12: Deployment ──────────────────────────────────────────────

function generateDeployment() {
  return `${generateSectionBanner(12, "Deployment", "Single command deploy — health checks, graceful shutdown, restart logic")}
function registerDeploymentRoutes(app) {
  app.get(CONFIG.deployment.healthCheckPath, (_req, res) => {
    const uptime = process.uptime();
    const memory = process.memoryUsage();
    res.json({
      ok: true,
      status: 'healthy',
      uptime: Math.floor(uptime),
      memory: {
        rss: Math.floor(memory.rss / 1024 / 1024) + 'MB',
        heap: Math.floor(memory.heapUsed / 1024 / 1024) + 'MB',
      },
      subsystems: Object.fromEntries(
        Object.entries(STATE.subsystemMetrics).map(([k, v]) => [k, { load: (v.load * 100).toFixed(1) + '%', threads: v.threads }])
      ),
      repairCortex: {
        patchesApplied: STATE.subsystemMetrics.repair.patchesApplied,
        knowledgeBaseSize: STATE.repairKnowledgeBase.size,
        avoidancePatternsCount: STATE.avoidancePatterns.size,
      },
      bootTime: STATE.bootTime,
    });
  });

  app.get('/api/status', (_req, res) => {
    res.json({
      ok: true,
      threadManager: threadManager.getStatus(),
      repairLog: STATE.repairLog.slice(-20),
      testResults,
    });
  });
}

function gracefulShutdown(signal) {
  log.info(\`Received \${signal}. Starting graceful shutdown...\`);

  // Stop accepting new connections
  if (STATE.server) {
    STATE.server.close(() => {
      log.info('HTTP server closed');
    });
  }

  // Close WebSocket connections
  if (STATE.wss) {
    for (const [, client] of wsClients) {
      client.close(1001, 'Server shutting down');
    }
  }

  // Stop thread manager
  threadManager.stop();

  // Close database
  if (STATE.db) {
    STATE.db.close();
    log.info('Database closed');
  }

  setTimeout(() => {
    log.info('Shutdown complete');
    process.exit(0);
  }, CONFIG.deployment.gracefulShutdownMs);
}

function generateDockerfile() {
  return \`FROM node:20-alpine
WORKDIR /app
COPY package*.json ./
RUN npm ci --production
COPY . .
EXPOSE \${CONFIG.port}
HEALTHCHECK --interval=30s --timeout=5s CMD wget -qO- http://localhost:\${CONFIG.port}\${CONFIG.deployment.healthCheckPath} || exit 1
CMD ["node", "\${__filename}"]
\`;
}

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));
`;
}

// ── Section 13: Repair Cortex ───────────────────────────────────────────

function generateRepairCortex() {
  return `${generateSectionBanner(13, "Repair Cortex", "Self-healing immune system — CANNOT BE DISABLED")}
/**
 * Three-phase repair cycle on the thread manager's tick:
 *   Phase 1 — Prophet: Predictive anomaly detection
 *   Phase 2 — Surgeon: Root cause diagnosis + automated fix
 *   Phase 3 — Guardian: Post-fix regression monitoring
 *
 * Every repair event generates a DTU. Same error never requires diagnosis twice.
 * With concordNode: true, repair DTUs propagate to the mesh for collective immunity.
 */

const repairCortex = {
  _watchList: new Map(),
  _metrics_history: new Map(),

  // ── Phase 1: Prophet ──────────────────────────────────────────────
  prophet: {
    analyze: () => {
      const anomalies = [];
      const metrics = STATE.subsystemMetrics;

      for (const [subsystem, m] of Object.entries(metrics)) {
        // Track metric history for trend analysis
        if (!repairCortex._metrics_history.has(subsystem)) {
          repairCortex._metrics_history.set(subsystem, []);
        }
        const history = repairCortex._metrics_history.get(subsystem);
        history.push({ ...m, timestamp: Date.now() });
        if (history.length > ${REPAIR_CORTEX.PHASES.PROPHET.trendAnalysisDepth}) history.shift();

        // Error rate spike detection
        if (m.errors > 0 && history.length > 10) {
          const recentErrors = history.slice(-10).reduce((sum, h) => sum + (h.errors || 0), 0);
          const avgErrors = history.reduce((sum, h) => sum + (h.errors || 0), 0) / history.length;
          if (recentErrors > avgErrors * 2 && recentErrors > 3) {
            anomalies.push({
              subsystem,
              type: 'error_rate_spike',
              severity: 'high',
              message: \`Error rate spike in \${subsystem}: \${recentErrors} recent vs \${avgErrors.toFixed(1)} avg\`,
              metric: { recentErrors, avgErrors },
            });
          }
        }

        // Response time degradation
        if (m.responseTimeAvg > 5000) {
          anomalies.push({
            subsystem,
            type: 'response_time_degradation',
            severity: 'medium',
            message: \`Slow responses in \${subsystem}: \${m.responseTimeAvg.toFixed(0)}ms avg\`,
          });
        }

        // Thread starvation
        if (m.threads === 0 && m.load > 0.3) {
          anomalies.push({
            subsystem,
            type: 'thread_starvation',
            severity: 'critical',
            message: \`Thread starvation in \${subsystem}: 0 threads but \${(m.load * 100).toFixed(0)}% load\`,
          });
        }

        // Memory leak pattern (sustained high load without proportional work)
        if (history.length >= 60) {
          const loadTrend = history.slice(-60).map(h => h.load);
          const increasing = loadTrend.every((v, i) => i === 0 || v >= loadTrend[i - 1] * 0.98);
          if (increasing && loadTrend[loadTrend.length - 1] > 0.5) {
            anomalies.push({
              subsystem,
              type: 'potential_memory_leak',
              severity: 'medium',
              message: \`Sustained increasing load in \${subsystem} — potential memory leak\`,
            });
          }
        }
      }

      return anomalies;
    },
  },

  // ── Phase 2: Surgeon ──────────────────────────────────────────────
  surgeon: {
    diagnose: (anomaly) => {
      const errorSig = \`\${anomaly.subsystem}:\${anomaly.type}\`;

      // Check knowledge base first — same error never diagnosed twice
      if (STATE.repairKnowledgeBase.has(errorSig)) {
        const known = STATE.repairKnowledgeBase.get(errorSig);
        log.repair(\`Known issue: \${errorSig} — applying cached fix\`);
        return { ...known, fromCache: true };
      }

      // Generate diagnosis based on anomaly type
      const diagnosis = {
        errorSignature: errorSig,
        rootCause: \`\${anomaly.type} detected in \${anomaly.subsystem}\`,
        suggestedFix: null,
        confidence: 0.7,
      };

      switch (anomaly.type) {
        case 'error_rate_spike':
          diagnosis.suggestedFix = 'increase_error_tolerance';
          diagnosis.rootCause = \`Error rate in \${anomaly.subsystem} exceeds normal threshold\`;
          break;
        case 'response_time_degradation':
          diagnosis.suggestedFix = 'allocate_more_threads';
          diagnosis.rootCause = \`\${anomaly.subsystem} response time degraded — likely under-resourced\`;
          break;
        case 'thread_starvation':
          diagnosis.suggestedFix = 'emergency_thread_allocation';
          diagnosis.rootCause = \`\${anomaly.subsystem} has zero threads with active load\`;
          diagnosis.confidence = 0.95;
          break;
        case 'potential_memory_leak':
          diagnosis.suggestedFix = 'gc_hint_and_monitor';
          diagnosis.rootCause = \`Sustained load increase in \${anomaly.subsystem} suggests memory leak\`;
          break;
      }

      return diagnosis;
    },

    applyFix: (diagnosis) => {
      if (!CONFIG.repair.surgeonAutoApply) {
        log.repair(\`Fix queued (auto-apply disabled): \${diagnosis.suggestedFix}\`);
        return { applied: false, reason: 'auto_apply_disabled' };
      }

      const metrics = STATE.subsystemMetrics;
      let applied = false;

      switch (diagnosis.suggestedFix) {
        case 'allocate_more_threads':
        case 'emergency_thread_allocation': {
          const subsystem = diagnosis.errorSignature.split(':')[0];
          if (metrics[subsystem]) {
            metrics[subsystem].threads = Math.min(metrics[subsystem].threads + 2, CONFIG.threads.maxThreads);
            applied = true;
          }
          break;
        }
        case 'increase_error_tolerance': {
          // Reset error counter as acknowledgment
          const subsystem = diagnosis.errorSignature.split(':')[0];
          if (metrics[subsystem]) {
            metrics[subsystem].errors = 0;
            applied = true;
          }
          break;
        }
        case 'gc_hint_and_monitor': {
          if (global.gc) global.gc();
          applied = true;
          break;
        }
      }

      if (applied) {
        log.repair(\`Fix applied: \${diagnosis.suggestedFix} for \${diagnosis.errorSignature}\`);
        STATE.subsystemMetrics.repair.patchesApplied++;
      }
      return { applied, fix: diagnosis.suggestedFix };
    },
  },

  // ── Phase 3: Guardian ─────────────────────────────────────────────
  guardian: {
    watch: (diagnosis, fixResult) => {
      if (!fixResult.applied) return;

      const watchId = diagnosis.errorSignature;
      repairCortex._watchList.set(watchId, {
        diagnosis,
        fixResult,
        startedAt: Date.now(),
        baselineErrors: STATE.subsystemMetrics[diagnosis.errorSignature.split(':')[0]]?.errors || 0,
      });

      log.repair(\`Guardian watching: \${watchId} for \${CONFIG.repair.guardianWatchWindowMs}ms\`);
    },

    checkWatched: () => {
      const now = Date.now();

      for (const [watchId, watch] of repairCortex._watchList) {
        if (now - watch.startedAt < CONFIG.repair.guardianWatchWindowMs) continue;

        const subsystem = watch.diagnosis.errorSignature.split(':')[0];
        const currentErrors = STATE.subsystemMetrics[subsystem]?.errors || 0;
        const errorDelta = currentErrors - watch.baselineErrors;

        if (errorDelta > watch.baselineErrors * ${REPAIR_CORTEX.PHASES.GUARDIAN.regressionThreshold}) {
          // Regression detected — rollback
          log.repair(\`REGRESSION detected for \${watchId} — rolling back\`);
          repairCortex.logRepairEvent(watch.diagnosis, watch.fixResult, 'rolled_back');
        } else {
          // Fix holds — log as permanent repair
          log.repair(\`Fix confirmed for \${watchId} — adding to knowledge base\`);
          STATE.repairKnowledgeBase.set(watchId, watch.diagnosis);
          repairCortex.logRepairEvent(watch.diagnosis, watch.fixResult, 'confirmed');
        }

        repairCortex._watchList.delete(watchId);
      }
    },
  },

  // ── Repair DTU Logging ────────────────────────────────────────────
  logRepairEvent: (diagnosis, fixResult, status) => {
    const event = {
      id: crypto.randomUUID(),
      errorSignature: diagnosis.errorSignature,
      rootCause: diagnosis.rootCause,
      fixApplied: fixResult.fix,
      subsystem: diagnosis.errorSignature.split(':')[0],
      severity: diagnosis.severity || 'medium',
      status,
      timestamp: new Date().toISOString(),
    };

    STATE.repairLog.push(event);
    if (STATE.repairLog.length > 1000) STATE.repairLog.shift();

    // Persist to database
    try {
      STATE.db.prepare(
        'INSERT INTO repair_events (error_signature, root_cause, fix_applied, subsystem, severity, status) VALUES (?, ?, ?, ?, ?, ?)'
      ).run(event.errorSignature, event.rootCause, event.fixApplied, event.subsystem, event.severity, event.status);
    } catch (err) {
      log.error('Failed to log repair event:', err.message);
    }

    // Propagate to mesh if Concord node
    if (CONFIG.concordNode && CONFIG.concordMesh.repairDTUPropagation) {
      repairCortex.propagateToMesh(event);
    }
  },

  // ── Avoidance Learning ────────────────────────────────────────────
  checkAvoidancePatterns: (codeOrQuery) => {
    const violations = [];
    for (const [sig, pattern] of STATE.avoidancePatterns) {
      if (typeof codeOrQuery === 'string' && codeOrQuery.includes(pattern.trigger)) {
        violations.push({ pattern: sig, description: pattern.description, severity: pattern.severity });
      }
    }
    return violations;
  },

  // ── Concord Mesh Propagation ──────────────────────────────────────
  propagateToMesh: (repairEvent) => {
    const dtu = {
      human: { summary: \`Repair: \${repairEvent.fixApplied} for \${repairEvent.errorSignature}\`, bullets: [repairEvent.rootCause] },
      core: { claims: [repairEvent.rootCause], definitions: { fix: repairEvent.fixApplied } },
      machine: { kind: 'repair_event', verifier: 'repair_cortex_v1' },
      artifact: { type: 'repair_dtu', size: JSON.stringify(repairEvent).length },
    };
    log.repair(\`Repair DTU propagated to mesh: \${repairEvent.errorSignature}\`);
    // In production, this would call mesh.send(dtu) via the Concord mesh transport
    return dtu;
  },

  // ── Main tick (called by thread manager) ──────────────────────────
  tick: () => {
    try {
      // Phase 1: Prophet
      const anomalies = repairCortex.prophet.analyze();

      // Phase 2: Surgeon
      const hourKey = new Date().toISOString().slice(0, 13);
      const repairsThisHour = STATE.repairLog.filter(r => r.timestamp?.startsWith(hourKey)).length;

      for (const anomaly of anomalies) {
        if (repairsThisHour >= CONFIG.repair.maxAutoRepairsPerHour) {
          log.repair('Max auto-repairs per hour reached — deferring');
          break;
        }
        const diagnosis = repairCortex.surgeon.diagnose(anomaly);
        const fixResult = repairCortex.surgeon.applyFix(diagnosis);
        repairCortex.guardian.watch(diagnosis, fixResult);
      }

      // Phase 3: Guardian checks
      repairCortex.guardian.checkWatched();
    } catch (err) {
      log.error('Repair cortex tick error:', err.message);
    }
  },
};
`;
}

// ── Boot Sequence ───────────────────────────────────────────────────────

function generateBoot() {
  return `
// ═══════════════════════════════════════════════════════════════════════════
// BOOT SEQUENCE — One process. One port. Everything alive.
// ═══════════════════════════════════════════════════════════════════════════

async function boot() {
  log.info(\`Booting \${CONFIG.appName}...\`);
  STATE.bootTime = new Date().toISOString();

  // 1. Database
  STATE.db = initDatabase();

  // 2. Express app
  const app = express();
  app.use(express.json());
  app.use((req, res, next) => {
    res.header('Access-Control-Allow-Origin', CONFIG.cors.origins.join(','));
    res.header('Access-Control-Allow-Methods', 'GET,POST,PUT,PATCH,DELETE,OPTIONS');
    res.header('Access-Control-Allow-Headers', 'Content-Type,Authorization');
    res.header('Access-Control-Allow-Credentials', 'true');
    if (req.method === 'OPTIONS') return res.sendStatus(204);
    next();
  });

  // 3. Rate limiting
  const rateLimitMap = new Map();
  app.use((req, res, next) => {
    const key = req.ip;
    const now = Date.now();
    const window = rateLimitMap.get(key) || { count: 0, start: now };
    if (now - window.start > CONFIG.rateLimits.windowMs) {
      window.count = 0;
      window.start = now;
    }
    window.count++;
    rateLimitMap.set(key, window);
    if (window.count > CONFIG.rateLimits.maxRequests) {
      return res.status(429).json({ error: 'Rate limit exceeded' });
    }
    next();
  });

  // 4. Register subsystems
  registerAuthRoutes(app);
  registerPaymentRoutes(app);
  registerAPIRoutes(app);
  registerFrontendRoutes(app);
  registerDeploymentRoutes(app);

  // 5. HTTP server
  const server = createServer(app);
  STATE.server = server;

  // 6. WebSocket
  initWebSocket(server);

  // 7. Background jobs
  runJobProcessor();

  // 8. Thread manager + Repair cortex
  const originalTick = threadManager.tick;
  threadManager.tick = () => {
    originalTick();
    repairCortex.tick();
  };
  threadManager.start();

  // 9. Run tests if --test flag
  if (process.argv.includes('--test')) {
    const results = await runTests();
    process.exit(results.failed > 0 ? 1 : 0);
  }

  // 10. Generate Dockerfile if configured
  if (CONFIG.deployment.generateDockerfile) {
    writeFileSync('Dockerfile', generateDockerfile());
    log.info('Dockerfile generated');
  }

  // 11. Start listening
  server.listen(CONFIG.port, CONFIG.host, () => {
    log.info(\`\${CONFIG.appName} is alive on \${CONFIG.host}:\${CONFIG.port}\`);
    log.info(\`Health check: http://localhost:\${CONFIG.port}\${CONFIG.deployment.healthCheckPath}\`);
    log.info(\`Repair Cortex: ACTIVE (cannot be disabled)\`);
    if (CONFIG.concordNode) log.info('Concord mesh node: ENABLED');
    log.info('One file. One process. Everything alive.');
  });
}

boot().catch((err) => {
  log.error('Boot failed:', err);
  process.exit(1);
});
`;
}

// ═══════════════════════════════════════════════════════════════════════════
// MAIN GENERATOR — Assembles all sections into one file
// ═══════════════════════════════════════════════════════════════════════════

/**
 * Generate a complete Forge application template.
 *
 * @param {object} options
 * @param {string} options.templateId - Which base template to use (blank, saas, ecommerce, etc.)
 * @param {object} options.config - Config overrides merged into FORGE_DEFAULT_CONFIG
 * @param {string[]} options.domainTables - Additional domain table names
 * @param {string[]} options.enabledSections - Which sections to include (all by default)
 * @returns {{ code: string, sections: object[], config: object }}
 */
export function generateForgeApp(options = {}) {
  const {
    templateId = "blank",
    config = {},
    domainTables = [],
    enabledSections = null,
  } = options;

  const template = FORGE_TEMPLATES[templateId] || FORGE_TEMPLATES.blank;
  const mergedConfig = deepMerge(JSON.parse(JSON.stringify(FORGE_DEFAULT_CONFIG)), config);

  // Repair cortex cannot be disabled
  mergedConfig.repair.enabled = true;

  const allTables = [
    ...(template.prefilledDomainTables || []),
    ...domainTables,
  ];

  const activeSections = enabledSections || template.sections;

  const parts = [];
  parts.push(generateBanner(mergedConfig.appName));

  if (activeSections.includes("dependencies")) parts.push(generateDependencies(mergedConfig));
  if (activeSections.includes("config")) parts.push(generateConfig(mergedConfig));
  if (activeSections.includes("database")) parts.push(generateDatabase(mergedConfig, allTables));
  if (activeSections.includes("auth")) parts.push(generateAuth());
  if (activeSections.includes("payments")) parts.push(generatePayments(mergedConfig));
  if (activeSections.includes("api")) parts.push(generateAPI());
  if (activeSections.includes("frontend")) parts.push(generateFrontend());
  if (activeSections.includes("websocket")) parts.push(generateWebSocket());
  if (activeSections.includes("jobs")) parts.push(generateJobs());
  if (activeSections.includes("threads")) parts.push(generateThreadManager());
  if (activeSections.includes("testing")) parts.push(generateTesting());
  if (activeSections.includes("deployment")) parts.push(generateDeployment());

  // Repair cortex is ALWAYS included — cannot be removed
  parts.push(generateRepairCortex());
  parts.push(generateBoot());

  return {
    code: parts.join("\n"),
    sections: FORGE_SECTIONS.filter((s) => activeSections.includes(s.id) || s.id === "repair"),
    config: mergedConfig,
    template: template.id,
    stats: {
      totalSections: activeSections.length + (activeSections.includes("repair") ? 0 : 1),
      linesEstimate: parts.join("\n").split("\n").length,
      domainTables: allTables.length,
    },
  };
}

/**
 * Validate a Forge app configuration.
 */
export function validateForgeConfig(config) {
  const errors = [];
  if (!config.appName) errors.push("appName is required");
  if (!config.database?.path && config.database?.driver !== "postgres") errors.push("database.path is required for SQLite");
  if (config.auth?.jwtSecret === "CHANGE_ME_IN_PRODUCTION") errors.push("auth.jwtSecret must be changed for production");
  if (config.stripe?.secretKey && !config.stripe.secretKey.startsWith("sk_")) errors.push("stripe.secretKey must start with sk_");
  if (config.repair?.enabled === false) errors.push("repair.enabled cannot be set to false — Repair Cortex is always active");
  return { valid: errors.length === 0, errors };
}

/**
 * Get section metadata for a template.
 */
export function getForgeTemplateSections(templateId = "blank") {
  const template = FORGE_TEMPLATES[templateId] || FORGE_TEMPLATES.blank;
  return FORGE_SECTIONS.filter((s) => template.sections.includes(s.id) || s.id === "repair");
}

/**
 * List available templates.
 */
export function listForgeTemplates() {
  return Object.values(FORGE_TEMPLATES);
}

// Deep merge helper
function deepMerge(target, source) {
  for (const key of Object.keys(source)) {
    if (source[key] && typeof source[key] === "object" && !Array.isArray(source[key])) {
      if (!target[key]) target[key] = {};
      deepMerge(target[key], source[key]);
    } else if (source[key] !== undefined) {
      target[key] = source[key];
    }
  }
  return target;
}
